# Configuration module for Mindcraft application.
import os
import yaml
from typing import Dict, Any

def get_config() -> Dict[str, Any]:
    """
    Load configuration from settings file and environment variables.

    Returns:
        Dictionary containing configuration values
    """
    # Default configuration
    config = {
        'app': {
            'name': 'Mindcraft',
            'version': '1.0.0',
            'debug': os.getenv('DEBUG', 'false').lower() == 'true'
        },
        'api': {
            'openai': {
                'model': os.getenv('OPENAI_MODEL', 'gpt-4o'),
                'temperature': float(os.getenv('OPENAI_TEMPERATURE', '0.7')),
                'max_tokens': int(os.getenv('OPENAI_MAX_TOKENS', '2000'))
            }
        },
        'content': {
            'fetch_timeout': int(os.getenv('FETCH_TIMEOUT', '30')),
            'max_retries': int(os.getenv('MAX_RETRIES', '3')),
            'rate_limit_delay': float(os.getenv('RATE_LIMIT_DELAY', '1.0'))
        },
        'security': {
            'enable_validation': True,
            'max_input_length': 10000
        },
        'paths': {
            'output_dir': os.getenv('OUTPUT_DIR', './output'),
            'interviews_dir': os.getenv('INTERVIEWS_DIR', './output/interviews'),
            'logs_dir': os.getenv('LOGS_DIR', './output/interview_logs')
        },
        'logging': {
            'level': os.getenv('LOG_LEVEL', 'INFO'),
            'format': '%(asctime)s - %(name)s - %(levelname)s - %(message)s'
        }
    }

    # Try to load from settings.yaml if it exists
    settings_path = os.path.join(os.path.dirname(__file__), 'settings.yaml')
    if os.path.exists(settings_path):
        with open(settings_path, 'r', encoding='utf-8') as f:
            yaml_config = yaml.safe_load(f)
            # Merge with defaults
            for key, value in yaml_config.items():
                if isinstance(value, dict) and key in config:
                    config[key].update(value)

